import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"明日方舟系列枪械","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/明日方舟系列枪械.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/明日方舟系列枪械.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/明日方舟系列枪械.md"};function o(d,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"明日方舟系列枪械",tabindex:"-1"},[t("明日方舟系列枪械 "),r("a",{class:"header-anchor",href:"#明日方舟系列枪械","aria-label":'Permalink to "明日方舟系列枪械"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),n('<h1 id="明日方舟系列枪械-1" tabindex="-1">明日方舟系列枪械 <a class="header-anchor" href="#明日方舟系列枪械-1" aria-label="Permalink to &quot;明日方舟系列枪械&quot;">​</a></h1><p>明日方舟系列枪械<br> 来自《明日方舟》中的各类枪械，由于泰拉世界中的科技树被源石技术高度绑架，导致泰拉人所用的枪械运作原理并非地球人所用的枪械相同，<br> 简单概括就是，由于泰拉人并没有点出【火药】的科技树，导致泰拉的枪械是用使用者本人【源石技艺】将子弹的底火击发而射出。更像是某种法杖</p><p>特殊的，使用明日方舟系列枪械时，如果无特殊说明，则攻击检定均为【智力+学识+学识下属专业：源石学+专注下属辅助专业-源石枪械】</p><p>==========<br> 【黑钢国际枪械】</p><p>黑钢国际“Black Steel(BS)”，是一家私人安全顾问公司，是主业安全顾问和私人保全的国际军事组织。前身为一支来自哥伦比亚的雇佣军。<br> 与其他自城邦战争获利的众多雇佣军不同，“黑钢国际”的初始成员大多是哥伦比亚独立战争时期的退役老兵。起初依附于哥伦比亚联邦，主要接受政府及企业合约。<br> 其核心业务是提供私人安全顾问与防务承包相关的服务。同时，其也是除拉特兰外唯一常驻配备铳枪的势力。</p><p>黑钢国际制式手铳<br> 价格：D+500<br> 黑钢国际为每位雇员提供的标准制式武器其一，其子弹口径为9mm，性能普通但实用，对使用者的源石技艺水平要求较低。<br> 经过主神改良之后，使用者即使不会源石技艺也能正常使用，其外形与寻常自动手枪基本无异。</p><p>由于射出的子弹经过武器内源石技艺的强化，你在使用该武器进行攻击检定时获得1点器械加值与1个额外附加成功。</p><p>类型：自动手枪<br> 伤害：6L<br> 特性：【高速5】【长点射】<br> 弹容量：11+1<br> 射程：30</p><p>======<br> 黑钢国际气动手铳<br> 价格：C+1000<br> 黑钢国际供优秀雇员购买和其在市场上的招牌商品之一，这款高性能铳械代表着黑钢最精尖的研发工艺，一经推出便成为当年的明星产品，深受佣兵喜爱。<br> 经过主神改良之后，使用者即使不会源石技艺也能正常使用，其结构与寻常自动手枪有所不同。</p><p>由于射出的子弹经过武器内源石技艺的强化，该武器的射程增加1倍，你在使用该武器进行攻击检定时获得2点附加成功。<br> 如果你拥有了“黑钢国际制式手枪”，则可以差价购买“黑钢国际气动手铳”。</p><p>类型：自动手枪<br> 伤害：11L<br> 特性：【高速5】【连射】<br> 弹容量：11+1<br> 射程：60（已计入增加）</p><p>========<br> 黑钢国际制式冲锋铳<br> 价格：D+750<br> 黑钢国际为突破和搜查雇员员工提供的标准制式武器，与手枪对比对使用者的源石技艺水平稍有提升，但更重要的还是枪法<br> 经过主神改良之后，使用者即使不会源石技艺也能正常使用，枪法不好另说，其外形与寻常冲锋枪基本无异。</p><p>由于射出的子弹经过武器内源石技艺的强化，武器的射程增加1倍，你在使用该武器进行攻击检定时获得1点附加成功</p><p>类型：冲锋枪<br> 伤害：6L<br> 特性：【高速5】【连射】装弹动作下降一级<br> 弹容量：30<br> 射程：40（已计入增加）</p><p>========<br> 黑钢国际制式突击步枪<br> 价格：D+500<br> 黑钢国际为精英雇员员工提供的制式武器，对使用者的源石技艺水平更精益求精，同时对身体素质的要求也有所提高。<br> 经过主神改良之后，使用者即使不会源石技艺也能正常使用，其外形与寻常使用5.56mm口径的突击步枪无异。</p><p>由于射出的子弹经过武器内源石技艺的强化，你在使用该武器进行攻击时额外获得【破甲2】，攻击检定获得1点附加成功</p><p>类型：步枪<br> 伤害：7L<br> 特性：【高速5】【破甲2】【长点射】 特殊子弹器械减值-1<br> 弹容量：30<br> 射程：150</p><p>========<br> 【拉特兰枪械】</p><p>“从不停歇的铳炮声，抵御着苦痛幽暗。”<br> 铳是一种构造独特的中远距离杀伤武器，据传最先由拉特兰人发现，也因此成为了拉特兰的标志之一，但当地的铳械使用术对于外域来说过于先进和复杂。<br> 只有萨科塔人才会大量使用铳械，其他人则会选择更易于使用的远程武器。黑钢国际倒是个少数的例外。</p><p>L-FMC 357转轮手铳<br> 价格：D+500<br> 拉特兰铳械制造中心研究的点357口径手枪，萨科塔人必备，在拉特兰甚至能看到人手一把的爆款手枪<br> 经过主神改良之后，哪怕使用者既不会源石技艺又不是拉特兰人也能正常使用，其外形与寻常左轮手枪基本无异。</p><p>由于射出的子弹经过武器内源石技艺的强化，该武器在攻击上获得2DP的器械加成，进行攻击检定时获得1点附加成功。</p><p>类型：左轮手枪<br> 伤害：7L<br> 特性：【高速5】装弹动作上升一级<br> 弹容量：6<br> 射程：30</p><p>========<br> L-FMC Spuer50<br> 价格：D+750<br> 拉特兰铳械制造中心研究的点50口径手枪，硕大的枪声、极强的威力与后坐力，无时无刻不在宣扬着作为萨科塔人的原始暴力。<br> 但据说，大部分萨科塔人对这种新式结构的铳械一点都不感兴趣。<br> 经过主神改良之后，哪怕使用者既不会源石技艺又不是拉特兰人也能正常使用，其外形与沙漠之鹰手枪雷同。</p><p>由于射出的子弹经过武器内源石技艺的强化，你在使用该武器进行攻击检定时获得2点附加成功。</p><p>类型：自动手枪<br> 伤害：6L<br> 特性：【高速5】【短点射】<br> 弹容量：6<br> 射程：30</p><p>========<br> L-FMC M1887<br> 价格：D+500<br> 拉特兰铳械制造中心研究使用12号霰弹的霰弹枪，疑似是萨科塔人的考古产品，但其可靠的性能还是令其广受萨科塔人的喜好。<br> 经过主神改良之后，哪怕使用者既不会源石技艺又不是拉特兰人也能正常使用，其细节与M1887霰弹枪基本一致，除了扳机结构。</p><p>由于射出的子弹经过武器内源石技艺的强化，你在使用该武器进行攻击时额外获得【威猛2】，攻击检定获得1点附加成功</p><p>类型：霰弹枪<br> 伤害：7L<br> 特性：【高速5】【威猛2】【长点射】<br> 攻击距离不超过15米内的单位时获得2威猛<br> 弹容量：11+1<br> 射程：40</p><p>========<br> 【其他势力枪械】<br> 这片大地上有着许多苦难和谜团，还有许多未知的人和事等待着探索，<br> 随着故事的进行，这片大地的所有人物、所有历史、所有谜团，总有一天会完整的展现在我们面前。</p><p>焚毁者-火焰喷射装置【深池】<br> 价格：D+500<br> 来自深池部队中使用火焰喷射装置的特殊部队。他们谨记着领袖的教诲，想在无尽的燃烧中重塑大地。<br> 经过主神的安全性改造，现在焚毁者的燃料罐不再那么容易爆炸了。<br> 特殊的，该枪械使用正常的射击攻击检定，在进行射击检定时获得1DP器械加值。</p><p>类型：喷火器<br> 伤害：5L<br> 特性：【高速2】【破甲2】【双手】【连射】<br> 伤害类型【火焰】，攻击附带2点燃烧点数，标准豁免<br> 弹容量：30<br> 射程：90</p><p>========</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',34)])])}const f=p(s,[["render",o]]);export{m as __pageData,f as default};
